const source = $json;
const p = source.pipeline || {};
const allowed = new Set(['OFFLINE', 'VALIDATE', 'DRY_RUN', 'LIVE']);
const requested = p.execution_mode;
const executionMode = typeof requested === 'string' && allowed.has(requested) ? requested : 'OFFLINE';
return [{json:{
  ...source,
  pipeline: {
    ...p,
    execution_mode: executionMode,
    dry_run: p.dry_run === false ? false : true,
    founder_write_approved: p.founder_write_approved === true,
    credentials_configured: p.credentials_configured === true
  }
}}];

const mode = $json.pipeline?.execution_mode === 'VALIDATE' ? 'VALIDATE' : 'OFFLINE';
return [{json:{
  document_id: $json.id || null,
  status: mode === 'VALIDATE' ? 'validate_local_only' : 'offline_local_only',
  execution_mode: mode,
  network_performed: false,
  write_performed: false,
  local_validation_required: true,
  validation_scope: ['manifest', 'registry', 'schema', 'workflows', 'secrets', 'execution_mode'],
  validation_command: 'python3 scripts/validate_manifest.py'
}}];

const doc = $json;
const p = doc.pipeline || {};
if (p.execution_mode !== 'DRY_RUN' && p.execution_mode !== 'LIVE') {
  throw new Error('Network access blocked by ExecutionMode.');
}
const requiredStrings = [
  'github_owner', 'github_repo', 'branch', 'expected_repository',
  'expected_branch', 'manifest_path', 'schema_path', 'template_path', 'manifest_version'
];
for (const key of requiredStrings) {
  const value = p[key];
  if (typeof value !== 'string' || !value.trim() || value.includes('CONFIGURE_')) {
    throw new Error(`Repository configuration invalid: ${key}`);
  }
}
const actualRepository = `${p.github_owner}/${p.github_repo}`;
if (p.expected_repository !== actualRepository) throw new Error('Repository identity mismatch.');
if (p.expected_branch !== p.branch) throw new Error('Branch identity mismatch.');
if (p.manifest_path !== 'n8n/config/ATLAS_MASTER_MANIFEST.json') throw new Error('Manifest path mismatch.');
if (p.schema_path !== 'atlas/DOCUMENT_OUTPUT_SCHEMA.json') throw new Error('Schema path mismatch.');
if (p.template_path !== 'atlas/DOCUMENT_TEMPLATE.md') throw new Error('Template path mismatch.');
const safePath = (value) => {
  if (typeof value !== 'string' || !value || value.startsWith('/') || value.includes('\\\\')) return false;
  const parts = value.split('/');
  return !parts.some(part => !part || part === '.' || part === '..');
};
for (const key of ['manifest_path', 'schema_path', 'template_path']) {
  if (!safePath(p[key])) throw new Error(`Unsafe repository path: ${key}`);
}
const governancePaths = p.required_governance_paths;
if (!Array.isArray(governancePaths) || !governancePaths.length || new Set(governancePaths).size !== governancePaths.length) {
  throw new Error('Required governance paths are missing or duplicated.');
}
for (const path of governancePaths) {
  if (!safePath(path)) throw new Error(`Unsafe governance path: ${path}`);
}
for (const required of ['PROJECT_BIBLE.md', 'AGENTS.md']) {
  if (!governancePaths.includes(required)) throw new Error(`Missing mandatory governance path: ${required}`);
}
const headers = {
  Accept: 'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28',
  Authorization: `Bearer ${$env.GITHUB_TOKEN}`
};
const encodePath = (path) => path.split('/').map(encodeURIComponent).join('/');
async function fetchRequired(path, identity) {
  if (!safePath(path)) throw new Error(`Unsafe required context path: ${path}`);
  const url = `https://api.github.com/repos/${encodeURIComponent(p.github_owner)}/${encodeURIComponent(p.github_repo)}/contents/${encodePath(path)}?ref=${encodeURIComponent(p.branch)}`;
  let payload;
  try {
    payload = await this.helpers.httpRequest({method: 'GET', url, headers, json: true});
  } catch (error) {
    throw new Error(`Required context read failed for ${identity}: ${error.message}`);
  }
  if (!payload || payload.type !== 'file' || payload.path !== path || payload.encoding !== 'base64') {
    throw new Error(`Required context identity mismatch for ${identity}`);
  }
  if (typeof payload.content !== 'string' || !payload.content.trim()) {
    throw new Error(`Required context is empty for ${identity}`);
  }
  const content = Buffer.from(payload.content.replace(/\n/g, ''), 'base64').toString('utf8');
  if (!content.trim()) throw new Error(`Required context decoded empty for ${identity}`);
  return {path, sha: payload.sha || null, content};
}
const manifestFile = await fetchRequired.call(this, p.manifest_path, 'Atlas manifest');
if (p.manifest_sha && manifestFile.sha !== p.manifest_sha) throw new Error('Manifest integrity mismatch.');
let manifest;
try {
  manifest = JSON.parse(manifestFile.content);
} catch (error) {
  throw new Error(`Manifest parse failed: ${error.message}`);
}
if (!manifest.atlas || manifest.atlas.version !== p.manifest_version || !Array.isArray(manifest.documents)) {
  throw new Error('Manifest version or structure mismatch.');
}
const byId = new Map();
const byPath = new Map();
for (const entry of manifest.documents) {
  if (!entry || typeof entry.id !== 'string' || !/^[A-Z]{2,3}-\d{3}$/.test(entry.id)) {
    throw new Error('Manifest contains an invalid document identity.');
  }
  if (byId.has(entry.id)) throw new Error(`Duplicate manifest document ID: ${entry.id}`);
  if (!safePath(entry.path)) throw new Error(`Unsafe manifest document path: ${entry.id}`);
  if (byPath.has(entry.path)) throw new Error(`Duplicate manifest document path: ${entry.path}`);
  byId.set(entry.id, entry);
  byPath.set(entry.path, entry.id);
}
const entry = byId.get(doc.id);
if (!entry) throw new Error(`Unknown document ID: ${doc.id}`);
const comparable = ['id', 'title', 'domain', 'path', 'minimum_words'];
for (const key of comparable) {
  if (doc[key] !== entry[key]) throw new Error(`Document registry mismatch: ${key}`);
}
if (!doc.registry_entry || doc.registry_entry.id !== entry.id || doc.registry_entry.path !== entry.path) {
  throw new Error('Document registry entry is missing or inconsistent.');
}
if (p.document_index && (!p.document_index[entry.id] || p.document_index[entry.id].path !== entry.path)) {
  throw new Error('Passed document index does not match the manifest.');
}
const dependencyIds = entry.dependencies || [];
if (!Array.isArray(dependencyIds) || new Set(dependencyIds).size !== dependencyIds.length) {
  throw new Error('Declared dependencies are malformed or duplicated.');
}
const schemaFile = await fetchRequired.call(this, p.schema_path, 'canonical output schema');
const templateFile = await fetchRequired.call(this, p.template_path, 'canonical document template');
let schema;
try {
  schema = JSON.parse(schemaFile.content);
} catch (error) {
  throw new Error(`Canonical schema parse failed: ${error.message}`);
}
if (schema.$schema !== 'https://json-schema.org/draft/2020-12/schema' || schema.properties?.schema_version?.const !== '1.0.0') {
  throw new Error('Canonical schema version mismatch.');
}
const requiredTemplateTokens = ['{{DOCUMENT_ID}}', '{{TITLE}}', '{{DOMAIN}}', '{{OWNER}}', '{{DEPENDENCIES}}', '{{MINIMUM_WORDS}}'];
for (const token of requiredTemplateTokens) {
  if (!templateFile.content.includes(token)) throw new Error(`Canonical template token missing: ${token}`);
}
const governance = {};
for (const path of governancePaths) {
  const loaded = await fetchRequired.call(this, path, `governance ${path}`);
  if (loaded.content.trim().length < 40) throw new Error(`Mandatory governance content is empty: ${path}`);
  governance[path] = loaded;
}
const dependencies = {};
for (const dependencyId of dependencyIds) {
  const dependencyEntry = byId.get(dependencyId);
  if (!dependencyEntry) throw new Error(`Unknown dependency ID: ${dependencyId}`);
  const loaded = await fetchRequired.call(this, dependencyEntry.path, `dependency ${dependencyId}`);
  const escapedId = dependencyId.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const identityPattern = new RegExp(`(?:^#\\s+${escapedId}\\b|^Document ID:\\s*${escapedId}\\s*$)`, 'm');
  if (!identityPattern.test(loaded.content)) throw new Error(`Wrong file identity for dependency ${dependencyId}`);
  dependencies[dependencyId] = {...loaded, registry_entry: dependencyEntry};
}
return [{json:{
  ...doc,
  registry_entry: entry,
  dependencies: dependencyIds,
  required_sections: entry.required_sections || [],
  context: {
    repository: p.expected_repository,
    branch: p.expected_branch,
    manifest: {path: manifestFile.path, sha: manifestFile.sha, version: manifest.atlas.version},
    schema: schema,
    schema_source: {path: schemaFile.path, sha: schemaFile.sha},
    template: templateFile.content,
    template_source: {path: templateFile.path, sha: templateFile.sha},
    governance,
    dependencies
  }
}}];

const d = $json;
const schema = d.context?.schema;
if (!schema || !d.context?.template) throw new Error('Canonical schema or template context is missing.');
const prompt = `You are the governed enterprise-document generator for Damavand Steel.

Return exactly one JSON object conforming to the canonical JSON Schema below.
Do not return Markdown, code fences, commentary, or undeclared properties.
The sections object must contain exactly the required section keys. Every section value must be a non-empty string.
dependencies_used must contain exactly the declared dependency IDs.
schema_version must be "1.0.0", status must be "draft", and version must be "0.1.0".

DOCUMENT REGISTRY ENTRY
${JSON.stringify(d.registry_entry)}

DECLARED DEPENDENCIES
${JSON.stringify(d.dependencies || [])}

CANONICAL OUTPUT SCHEMA
${JSON.stringify(schema)}

CANONICAL DOCUMENT TEMPLATE
${d.context.template}

GOVERNANCE CONTEXT
${JSON.stringify(Object.fromEntries(Object.entries(d.context.governance || {}).map(([path, value]) => [path, value.content])))}

DEPENDENCY CONTEXT
${JSON.stringify(Object.fromEntries(Object.entries(d.context.dependencies || {}).map(([id, value]) => [id, value.content])))}

NON-NEGOTIABLE RULES
1. Preserve Founder decisions and repository governance.
2. Do not invent unresolved business facts; record them in open_questions and the open_questions section.
3. Meet the registered minimum word count across section content.
4. Do not use TODO, TBD, PLACEHOLDER, or empty content.
5. Keep document_id and title identical to the registry entry.
6. Return valid JSON only.`;
return [{json:{...d, prompt}}];

const source = $('Build Generation Prompt').first().json;
let text = $json.output_text || '';
if (!text && Array.isArray($json.output)) {
  for (const output of $json.output) {
    for (const content of (output.content || [])) {
      if (typeof content.text === 'string') text += content.text;
    }
  }
}
if (typeof text !== 'string' || !text.trim()) throw new Error('Generated structured output is empty.');
let generated;
try {
  const match = text.match(/\{[\s\S]*\}/);
  generated = JSON.parse(match ? match[0] : text);
} catch (error) {
  throw new Error(`Generated structured output parse failed: ${error.message}`);
}
if (!generated || typeof generated !== 'object' || Array.isArray(generated)) {
  throw new Error('Generated structured output must be an object.');
}
return [{json:{...source, generated}}];

const d = $json;
const g = d.generated;
const schema = d.context?.schema;
const errors = [];
const isObject = value => value && typeof value === 'object' && !Array.isArray(value);
if (!isObject(schema) || !isObject(schema.properties)) errors.push('canonical schema missing');
if (!isObject(g)) errors.push('output is not an object');
if (!errors.length) {
  const allowed = Object.keys(schema.properties);
  const required = schema.required || [];
  for (const key of required) {
    if (!Object.prototype.hasOwnProperty.call(g, key)) errors.push(`missing required property: ${key}`);
  }
  for (const key of Object.keys(g)) {
    if (!allowed.includes(key)) errors.push(`undeclared property: ${key}`);
  }
  if (g.schema_version !== schema.properties.schema_version?.const) errors.push('schema version mismatch');
  if (g.document_id !== d.id || !/^[A-Z]{2,3}-\d{3}$/.test(String(g.document_id || ''))) errors.push('invalid document identity');
  if (g.title !== d.title || typeof g.title !== 'string' || !g.title.trim()) errors.push('invalid document title');
  if (g.status !== 'draft' || !schema.properties.status.enum.includes(g.status)) errors.push('invalid status');
  if (g.version !== '0.1.0') errors.push('invalid version');
  const expectedSections = d.required_sections || [];
  const schemaSections = schema.properties.sections || {};
  if (!isObject(g.sections)) {
    errors.push('malformed sections');
  } else {
    const actualSections = Object.keys(g.sections);
    for (const key of expectedSections) {
      if (!Object.prototype.hasOwnProperty.call(g.sections, key)) errors.push(`missing section: ${key}`);
      else if (typeof g.sections[key] !== 'string' || !g.sections[key].trim()) errors.push(`empty required content: ${key}`);
    }
    for (const key of actualSections) {
      if (!expectedSections.includes(key) || !Object.prototype.hasOwnProperty.call(schemaSections.properties || {}, key)) {
        errors.push(`undeclared section: ${key}`);
      }
    }
  }
  for (const key of ['dependencies_used', 'entities_referenced', 'rules_referenced', 'open_questions', 'acceptance_criteria']) {
    if (Object.prototype.hasOwnProperty.call(g, key) && (!Array.isArray(g[key]) || g[key].some(value => typeof value !== 'string'))) {
      errors.push(`malformed array: ${key}`);
    }
  }
  const declared = [...(d.dependencies || [])].sort();
  const used = Array.isArray(g.dependencies_used) ? [...g.dependencies_used] : [];
  if (new Set(used).size !== used.length || JSON.stringify([...used].sort()) !== JSON.stringify(declared)) {
    errors.push('dependencies_used mismatch');
  }
  const template = d.context?.template;
  if (typeof template !== 'string' || !template.trim()) errors.push('canonical template missing');
  const words = isObject(g.sections)
    ? Object.values(g.sections).join(' ').trim().split(/\s+/).filter(Boolean).length
    : 0;
  if (words < Number(d.minimum_words || 0)) errors.push(`word_count ${words} below ${d.minimum_words}`);
  const serialized = JSON.stringify(g);
  if (/\b(TODO|TBD|PLACEHOLDER)\b/i.test(serialized)) errors.push('forbidden placeholder token found');
}
const wordCount = isObject(g?.sections)
  ? Object.values(g.sections).join(' ').trim().split(/\s+/).filter(Boolean).length
  : 0;
return [{json:{
  ...d,
  canonical_output: g,
  validation: {
    passed: errors.length === 0,
    errors,
    word_count: wordCount,
    schema_version: g?.schema_version || null,
    required_context_loaded: Boolean(d.context?.manifest && d.context?.schema && d.context?.template && d.context?.governance)
  }
}}];

const d=$json;
const p=d.pipeline || {};
const allowed = new Set(['OFFLINE', 'VALIDATE', 'DRY_RUN', 'LIVE']);
const mode = typeof p.execution_mode === 'string' && allowed.has(p.execution_mode) ? p.execution_mode : 'OFFLINE';
const effectiveDryRun=p.dry_run !== false;
const founderApproved=p.founder_write_approved === true;
const credentialsConfigured=p.credentials_configured === true;
const workflowActive=$workflow.active === true;
let status='write_gate_blocked';
if(mode === 'DRY_RUN') status='dry_run_blocked_write';
else if(mode !== 'LIVE') status='execution_mode_blocked_write';
else if(effectiveDryRun) status='dry_run_blocked_write';
else if(!founderApproved) status='founder_approval_blocked_write';
else if(!credentialsConfigured) status='credentials_blocked_write';
else if(!workflowActive) status='inactive_workflow_blocked_write';
return [{json:{
  document_id:d.id,
  status,
  write_performed:false,
  execution_mode:mode,
  dry_run:effectiveDryRun,
  founder_write_approved:founderApproved,
  credentials_configured:credentialsConfigured,
  workflow_active:workflowActive,
  validation_status:'passed',
  path:d.path
}}];

const d=$('Structural Validator').first().json;
return [{json:{
  document_id:d.id,
  status:'review_required',
  validation_status:'passed',
  write_performed:true,
  execution_mode:'LIVE',
  path:d.path,
  word_count:d.validation.word_count,
  github_commit:$json.commit?.sha || $json.content?.sha || null
}}];

const d = $json;
if (d.validation?.passed !== true) throw new Error('Rendering blocked: canonical output is invalid.');
const output = d.canonical_output;
let markdown = d.context.template;
const replacements = {
  '{{DOCUMENT_ID}}': output.document_id,
  '{{TITLE}}': output.title,
  '{{DOMAIN}}': d.domain,
  '{{OWNER}}': d.owner,
  '{{DEPENDENCIES}}': (d.dependencies || []).join(', ') || 'None',
  '{{MINIMUM_WORDS}}': String(d.minimum_words),
  '{{VERSION}}': output.version
};
for (const [token, value] of Object.entries(replacements)) {
  markdown = markdown.split(token).join(String(value ?? ''));
}
const specialHeadings = {
  seo_impact: 'SEO Impact',
  ai_usage: 'AI Usage',
  wordpress_mapping: 'WordPress Mapping'
};
const headingFor = key => specialHeadings[key] || key.split('_').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ');
for (const key of d.required_sections || []) {
  const marker = `## ${headingFor(key)}`;
  const parts = markdown.split(marker);
  if (parts.length !== 2) throw new Error(`Template heading missing or duplicated: ${marker}`);
  markdown = `${parts[0]}${marker}\n\n${output.sections[key].trim()}${parts[1]}`;
}
if (/\{\{[^}]+\}\}/.test(markdown)) throw new Error('Template rendering left unresolved tokens.');
if (!markdown.trim()) throw new Error('Deterministic Markdown rendering produced empty output.');
return [{json:{...d, markdown: markdown.trim() + '\n'}}];
